import threading


class FooBar:
    def __init__(self, n):
        self.n = n
        self.turn_foo = True
        self.cv = threading.Condition()

    def foo(self, printFoo):
        for _ in range(self.n):
            with self.cv:
                self.cv.wait_for(lambda: self.turn_foo)
                printFoo()
                self.turn_foo = False
                self.cv.notify_all()

    def bar(self, printBar):
        for _ in range(self.n):
            with self.cv:
                self.cv.wait_for(lambda: not self.turn_foo)
                printBar()
                self.turn_foo = True
                self.cv.notify_all()

